import { X, Plus, Calendar, CheckSquare, Clock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { formatDuration, formatTime } from '../utils/timeFormatters';
import type { CalendarEvent, Task, TimeEntry } from '../types';

interface DayDetailModalProps {
  dateKey: string;
  events: CalendarEvent[];
  tasks: Task[];
  timeEntries?: TimeEntry[];
  totalDuration?: number;
  onClose: () => void;
  onCreateEvent: () => void;
  onEditEvent?: (event: CalendarEvent, dateKey: string) => void;
  onEditEntry?: (entry: TimeEntry) => void;
}

/**
 * DayDetailModal Component
 * Shows all events and tasks for a specific day
 * Provides quick access to add new events or view/edit existing ones
 */
export function DayDetailModal({
  dateKey,
  events,
  tasks,
  timeEntries = [],
  totalDuration = 0,
  onClose,
  onCreateEvent,
  onEditEvent,
  onEditEntry,
}: DayDetailModalProps) {
  const navigate = useNavigate();

  // Parse date key (YYYY-M-D format) to display formatted date
  const [year, month, day] = dateKey.split('-').map(Number);
  const displayDate = new Date(year, month - 1, day);
  const formattedDate = displayDate.toLocaleDateString('en-US', {
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    year: 'numeric',
  });

  const handleEventClick = (event: CalendarEvent) => {
    if (onEditEvent) {
      onEditEvent(event, dateKey);
      onClose();
    }
  };

  const handleTaskClick = (task: Task) => {
    // Navigate to tasks page with task ID to open it
    navigate('/tasks', { state: { selectedTaskId: task.id } });
    onClose();
  };

  const handleAddEvent = () => {
    onCreateEvent();
    onClose();
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high':
        return 'text-status-error';
      case 'medium':
        return 'text-status-warning';
      default:
        return 'text-status-success';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Modal */}
      <div className="relative z-10 w-full max-w-lg mx-4 bg-surface-light dark:bg-surface-dark rounded-card shadow-modal max-h-[80vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark">
          <div>
            <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
              {formattedDate}
            </h2>
            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
              {events.length} event{events.length !== 1 ? 's' : ''}, {tasks.length} task{tasks.length !== 1 ? 's' : ''}
              {timeEntries.length > 0 && `, ${timeEntries.length} time ${timeEntries.length === 1 ? 'entry' : 'entries'}`}
              {totalDuration > 0 && ` ‚Ä¢ ${formatDuration(totalDuration, { showSeconds: false })}`}
            </p>
          </div>
          <button
            onClick={onClose}
            className="p-1.5 rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-all duration-standard ease-smooth"
            aria-label="Close"
          >
            <X className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {/* Events Section */}
          <div>
            <div className="flex items-center gap-2 mb-2">
              <Calendar className="w-3.5 h-3.5 text-accent-magenta dark:text-accent-cyan" />
              <h3 className="text-xs font-semibold text-text-light-primary dark:text-text-dark-primary">
                Events
              </h3>
            </div>
            {events.length > 0 ? (
              <div className="space-y-1.5">
                {events.map((event) => (
                  <button
                    key={event.id}
                    onClick={() => handleEventClick(event)}
                    className="w-full text-left p-2 rounded-button bg-accent-magenta/10 dark:bg-accent-cyan/10 border border-accent-magenta/20 dark:border-accent-cyan/20 hover:bg-accent-magenta/20 dark:hover:bg-accent-cyan/20 transition-all duration-standard ease-smooth"
                  >
                    <div className="font-medium text-xs text-text-light-primary dark:text-text-dark-primary">
                      {event.recurrence && 'üîÅ '}{event.title}
                    </div>
                    <div className="flex items-center gap-2 mt-0.5 text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
                      {event.isAllDay ? (
                        <span>All day</span>
                      ) : event.startTime && (
                        <span>
                          {event.startTime}
                          {event.endTime && ` - ${event.endTime}`}
                        </span>
                      )}
                      {event.location && (
                        <span className="truncate">üìç {event.location}</span>
                      )}
                    </div>
                    {event.description && (
                      <p className="mt-1 text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary line-clamp-2">
                        {event.description}
                      </p>
                    )}
                  </button>
                ))}
              </div>
            ) : (
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
                No events scheduled
              </p>
            )}
          </div>

          {/* Time Entries Section */}
          {timeEntries.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-2">
                <Clock className="w-3.5 h-3.5 text-accent-magenta dark:text-accent-cyan" />
                <h3 className="text-xs font-semibold text-text-light-primary dark:text-text-dark-primary">
                  Time Tracked
                </h3>
                {totalDuration > 0 && (
                  <span className="text-xs font-mono text-accent-magenta dark:text-accent-cyan">
                    {formatDuration(totalDuration, { showSeconds: false })}
                  </span>
                )}
              </div>
              <div className="space-y-1.5">
                {timeEntries.map((entry) => (
                  <button
                    key={entry.id}
                    onClick={() => onEditEntry?.(entry)}
                    className="w-full text-left p-2 rounded-button bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark hover:border-accent-magenta/50 dark:hover:border-accent-cyan/50 transition-all duration-standard ease-smooth"
                  >
                    <div className="font-medium text-xs text-text-light-primary dark:text-text-dark-primary">
