    66‚Üí
    67‚Üí  // Handle ICS import
    68‚Üí  const handleImport = async (file: File) => {
    69‚Üí    try {
    70‚Üí      const icsData = await readICSFile(file);
    71‚Üí      const result = importFromICS(icsData);
