    73‚Üí      if (result.success && result.events) {
    74‚Üí        const count = importEvents(result.events);
    75‚Üí        setImportStatus({ message: `Imported ${count} event${count !== 1 ? 's' : ''}`, type: 'success' });
    76‚Üí      } else {
