    94‚Üí        const monthEnd = new Date(year, month + 1, 0, 23, 59, 59);
    95‚Üí
    96‚Üí        await Promise.all([
    97‚Üí          loadEntries({
    98‚Üí            dateRange: 'custom',
    99‚Üí            startDate: monthStart.toISOString(),
   100‚Üí            endDate: monthEnd.toISOString(),
   101‚Üí            projectIds: [],
   102‚Üí            tags: [],
   103‚Üí            searchQuery: ''
   104‚Üí          }),
   105‚Üí          loadProjects()
   106‚Üí        ]);
   107‚Üí      } catch (error) {
   108‚Üí        console.error('Failed to load calendar data:', error);
   109‚Üí      } finally {
