   111‚Üí      }
   112‚Üí    };
   113‚Üí
   114‚Üí    loadData();
   115‚Üí  }, [loadEntries, loadProjects, year, month]);
   116‚Üí
   117‚Üí  const handlePrevious = () => {
   118‚Üí    if (viewMode === 'monthly') {
   119‚Üí      setCurrentDate(new Date(year, month - 1, 1));
   120‚Üí    } else if (viewMode === 'weekly') {
   121‚Üí      const newDate = new Date(currentDate);
   122‚Üí      newDate.setDate(newDate.getDate() - 7);
   123‚Üí      setCurrentDate(newDate);
   124‚Üí    } else if (viewMode === 'daily') {
