   126‚Üí      newDate.setDate(newDate.getDate() - 1);
   127‚Üí      setCurrentDate(newDate);
   128‚Üí    }
   129‚Üí    // Agenda view doesn't have prev/next (it's always forward-looking)
   130‚Üí  };
   131‚Üí
   132‚Üí  const handleNext = () => {
   133‚Üí    if (viewMode === 'monthly') {
   134‚Üí      setCurrentDate(new Date(year, month + 1, 1));
   135‚Üí    } else if (viewMode === 'weekly') {
   136‚Üí      const newDate = new Date(currentDate);
   137‚Üí      newDate.setDate(newDate.getDate() + 7);
   138‚Üí      setCurrentDate(newDate);
   139‚Üí    } else if (viewMode === 'daily') {
   140‚Üí      const newDate = new Date(currentDate);
   141‚Üí      newDate.setDate(newDate.getDate() + 1);
   142‚Üí      setCurrentDate(newDate);
   143‚Üí    }
   144‚Üí  };
   145‚Üí
   146‚Üí  const handleToday = () => {
   147‚Üí    setCurrentDate(new Date());
   148‚Üí  };
   149‚Üí
   150‚Üí  const handlePrint = () => {
   151‚Üí    window.print();
   152‚Üí  };
   153‚Üí
   154‚Üí  // Expand recurring and multi-day events for current month
   155‚Üí  // NOTE: Must be called before early return to maintain consistent hook order
   156‚Üí  const expandedEvents = useMemo(() => {
   157‚Üí    const result: Record<string, CalendarEvent[]> = {};
   158‚Üí
   159‚Üí    const monthStart = new Date(year, month, 1);
   160‚Üí    const monthEnd = new Date(year, month + 1, 0);
   161‚Üí
