   192‚Üí        <div className="text-text-light-secondary dark:text-text-dark-secondary">
   193‚Üí          Loading calendar...
   194‚Üí        </div>
   195‚Üí      </div>
   196‚Üí    );
   197‚Üí  }
   198‚Üí
   199‚Üí  // Get display text for current period
   200‚Üí  const getDisplayText = () => {
   201‚Üí    if (viewMode === 'monthly') {
   202‚Üí      return new Date(year, month, 1).toLocaleDateString('en-US', {
   203‚Üí        month: 'long',
   204‚Üí        year: 'numeric'
   205‚Üí      });
   206‚Üí    } else if (viewMode === 'weekly') {
   207‚Üí      const startOfWeek = new Date(currentDate);
   208‚Üí      startOfWeek.setDate(startOfWeek.getDate() - startOfWeek.getDay());
   209‚Üí      const endOfWeek = new Date(startOfWeek);
   210‚Üí      endOfWeek.setDate(endOfWeek.getDate() + 6);
   211‚Üí
   212‚Üí      if (startOfWeek.getMonth() === endOfWeek.getMonth()) {
   213‚Üí        return `${startOfWeek.toLocaleDateString('en-US', { month: 'long' })} ${startOfWeek.getDate()}-${endOfWeek.getDate()}, ${startOfWeek.getFullYear()}`;
   214‚Üí      } else {
   215‚Üí        return `${startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;
   216‚Üí      }
   217‚Üí    } else if (viewMode === 'daily') {
   218‚Üí      return currentDate.toLocaleDateString('en-US', {
   219‚Üí        weekday: 'long',
   220‚Üí        month: 'long',
   221‚Üí        day: 'numeric',
   222‚Üí        year: 'numeric'
   223‚Üí      });
   224‚Üí    } else {
   225‚Üí      // Agenda
   226‚Üí      return 'Upcoming Events';
   227‚Üí    }
   228‚Üí  };
   229‚Üí
   230‚Üí  // Get day of week for first day of month (0 = Sunday)
   231‚Üí  const firstDayOfWeek = new Date(year, month, 1).getDay();
   232‚Üí  const daysInMonth = new Date(year, month + 1, 0).getDate();
   233‚Üí
   234‚Üí  // Group entries by date
   235‚Üí  const entriesByDate = new Map<string, TimeEntry[]>();
   236‚Üí  entries.forEach(entry => {
   237‚Üí    const date = new Date(entry.startTime).toISOString().split('T')[0];
   238‚Üí    if (!entriesByDate.has(date)) {
   239‚Üí      entriesByDate.set(date, []);
   240‚Üí    }
   241‚Üí    entriesByDate.get(date)!.push(entry);
   242‚Üí  });
   243‚Üí
   244‚Üí  // Create calendar grid (for monthly view)
   245‚Üí  const calendarDays: (number | null)[] = [];
   246‚Üí  for (let i = 0; i < firstDayOfWeek; i++) {
   247‚Üí    calendarDays.push(null); // Empty cells before month starts
   248‚Üí  }
   249‚Üí  for (let day = 1; day <= daysInMonth; day++) {
   250‚Üí    calendarDays.push(day);
   251‚Üí  }
   252‚Üí
   253‚Üí  const handleDayClick = (dateKey: string) => {
   254‚Üí    // Click on a day opens the DayDetailModal
   255‚Üí    const dayEvents = expandedEvents[dateKey] || [];
   256‚Üí    const dayTasks = tasksByDate[dateKey] || [];
   257‚Üí
   258‚Üí    // Get time entries for this day (need to convert dateKey to ISO format)
   259‚Üí    const [year, month, day] = dateKey.split('-').map(Number);
   260‚Üí    const isoDateStr = `${year}-${month.toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
