              title="Print calendar"
              aria-label="Print calendar"
            >
              <Printer className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
            {/* Export/Import buttons */}
            <button
              onClick={handleExport}
              className="p-2 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded-buttontransition-all duration-standard ease-smooth no-print"
              title="Export to .ics file"
              aria-label="Export calendar"
            >
              <Download className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
            <button
              onClick={() => fileInputRef.current?.click()}
              className="p-2 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded-buttontransition-all duration-standard ease-smooth no-print"
              title="Import from .ics file"
              aria-label="Import calendar"
            >
              <Upload className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary" />
            </button>
            <input
              ref={fileInputRef}
              type="file"
              accept=".ics"
              className="hidden"
              onChange={(e) => {
                const file = e.target.files?.[0];
                if (file) {
                  handleImport(file);
                  e.target.value = ''; // Reset for re-import
                }
              }}
            />
          </div>

          {/* Right: Status message or placeholder */}
          <div className="w-[88px] flex items-center justify-end">
            {importStatus && (
              <span className={`text-xs px-2 py-1 rounded ${
                importStatus.type === 'success'
                  ? 'bg-status-success/20 text-status-success'
                  : 'bg-status-error/20 text-status-error'
              }`}>
                {importStatus.message}
              </span>
            )}
          </div>
        </div>

        {/* View Mode Switcher */}
        <div className="flex justify-center">
          <div className="flex gap-1 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-buttonp-1">
            <button
              onClick={() => setViewMode('monthly')}
              className={`px-3 py-1 rounded-buttontext-sm transition-all duration-standard ease-smooth ${
                viewMode === 'monthly'
                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
                  : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-neutral-800'
              }`}
            >
              Month
            </button>
            <button
              onClick={() => setViewMode('weekly')}
              className={`px-3 py-1 rounded-buttontext-sm transition-all duration-standard ease-smooth ${
                viewMode === 'weekly'
                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
                  : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-neutral-800'
              }`}
            >
              Week
            </button>
            <button
              onClick={() => setViewMode('daily')}
              className={`px-3 py-1 rounded-buttontext-sm transition-all duration-standard ease-smooth ${
                viewMode === 'daily'
                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
                  : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-neutral-800'
              }`}
            >
              Day
            </button>
            <button
              onClick={() => setViewMode('agenda')}
              className={`px-3 py-1 rounded-buttontext-sm transition-all duration-standard ease-smooth ${
                viewMode === 'agenda'
                  ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
                  : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-neutral-800'
