              // Standard format for calendar store (YYYY-M-D)
              const standardDateKey = `${year}-${month + 1}-${day}`;
              const dayEntries = entriesByDate.get(isoDateStr) || [];
              const dayEvents = expandedEvents[standardDateKey] || [];
              const dayTasks = tasksByDate[standardDateKey] || [];
              // Use local date comparison (not UTC via toISOString) to determine "today"
              const today = new Date();
              const isToday = year === today.getFullYear() && month === today.getMonth() && day === today.getDate();
              const totalDuration = dayEntries.reduce((sum, entry) => sum + entry.duration, 0);
              const hasContent = dayEntries.length > 0 || dayEvents.length > 0 || dayTasks.length > 0;

