                      : 'border-border-light dark:border-border-dark'
                  } ${
                    hasContent
                      ? 'bg-surface-light dark:bg-surface-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-surface-dark'
                  }`}
                  title={hasContent ? 'Click to view details' : 'Click to add event'}
                >
                  {/* Day Number */}
                  <div
                    className={`text-sm font-semibold mb-1 ${
                      isToday
                        ? 'text-accent-magenta dark:text-accent-cyan'
                        : 'text-text-light-primary dark:text-text-dark-primary'
                    }`}
                  >
                    {day}
                  </div>

                  {/* Compact Summary */}
                  {hasContent && (
                    <div className="space-y-1">
                      {/* Time Tracked */}
                      {totalDuration > 0 && (
                        <div className="flex items-center gap-1 text-xs text-accent-magenta dark:text-accent-cyan font-medium">
                          <Clock className="w-3 h-3" />
                          {formatDuration(totalDuration, { showSeconds: false })}
                        </div>
                      )}

                      {/* Entry Count */}
                      {dayEntries.length > 0 && (
                        <div className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary">
                          {dayEntries.length} {dayEntries.length === 1 ? 'entry' : 'entries'}
                        </div>
                      )}

                      {/* Event Count */}
                      {dayEvents.length > 0 && (
                        <div className="text-[10px] text-accent-purple dark:text-accent-purple">
                          üìÖ {dayEvents.length} {dayEvents.length === 1 ? 'event' : 'events'}
                        </div>
                      )}

                      {/* Task Count */}
                      {dayTasks.length > 0 && (
                        <div className="text-[10px] text-accent-blue">
                          üìã {dayTasks.length} {dayTasks.length === 1 ? 'task' : 'tasks'}
                        </div>
                      )}
                    </div>
                  )}

                  {/* Empty state hint */}
                  {!hasContent && (
                    <div className="text-[10px] text-text-light-tertiary dark:text-text-dark-tertiary opacity-0 group-hover:opacity-100">
                      Click to add
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        </div>
      ) : viewMode === 'weekly' ? (
        /* Weekly View */
        <WeekView
          currentDate={currentDate}
          events={expandedEvents}
          tasks={[]} // No tasks in time tracking context
          onDayClick={handleDayClick}
          onEventClick={handleEventClick}
          showTimeSlots={true}
        />
      ) : viewMode === 'daily' ? (
        /* Daily View */
        <DayView
          date={currentDate}
          events={expandedEvents[getStandardDateKey(currentDate)] || []}
          onEventClick={handleEventClick}
          onTimeSlotClick={() => {
            const dateKey = getStandardDateKey(currentDate);
            handleDayClick(dateKey);
          }}
        />
      ) : (
        /* Agenda/List View */
        <AgendaView
          events={expandedEvents}
          currentDate={currentDate}
          daysToShow={14}
          onEventClick={handleEventClick}
        />
      )}

      {/* Legend */}
      {projects.filter(p => p.active && !p.archived).length > 0 && (
        <div className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark p-4">
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
            Project Legend
          </h3>
          <div className="flex flex-wrap gap-3">
            {projects.filter(p => p.active && !p.archived).map(project => (
              <div key={project.id} className="flex items-center gap-2">
                <div
                  className="w-3 h-3 rounded"
                  style={{ backgroundColor: project.color }}
                />
                <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                  {project.name}
                </span>
              </div>
            ))}
            <div className="flex items-center gap-2">
              <div className="w-3 h-3 rounded-buttonbg-gray-400" />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                No Project
              </span>
            </div>
          </div>
        </div>
      )}

      {/* Day Detail Modal */}
      {dayDetailModal && (
        <DayDetailModal
          dateKey={dayDetailModal.dateKey}
          events={dayDetailModal.events}
          tasks={dayDetailModal.tasks}
          timeEntries={dayDetailModal.timeEntries}
          totalDuration={dayDetailModal.totalDuration}
          onClose={() => setDayDetailModal(null)}
          onCreateEvent={() => {
            if (onCreateEvent) {
              onCreateEvent(dayDetailModal.dateKey);
            }
          }}
          onEditEvent={onEditEvent}
          onEditEntry={onEditEntry}
        />
      )}
    </div>
  );
}

